sql:
SELECT source_type, source_name
FROM data_sources
WHERE source_type = 'log' AND sampling_rate > 1;

SELECT function_id, AVG(response_time) AS average_response_time
FROM performance_data
GROUP BY function_id;

SELECT user_name
FROM users
WHERE role = 'DevOps engineer';

SELECT user_id
FROM users
WHERE user_id NOT IN (
    SELECT user_id
    FROM user_roles
);

